local b64_0xl1Ill1 = {}
local char_0xl1I1II='ABCDEFGHIJKLMNOPQRSTUVWXYZabcdefghijklmnopqrstuvwxyz0123456789+/'
for i_0xI1IllI=1,#char_0xl1I1II do b64_0xl1Ill1[char_0xl1I1II:sub(i_0xI1IllI,i_0xI1IllI)] = i_0xI1IllI - 1 end

function b64_0xl1Ill1.dec_0x11ll11(d_0x11llIl)
