        local c_0xllIIII, c_0xll1II1 = 0, 0
        local has3 = true
        local has4 = true
        local ch3 = d_0x11llIl:sub(i_0xI1IllI+2,i_0xI1IllI+2)
        if ch3 == "=" then has3 = false else c_0xllIIII = b64_0xl1Ill1[ch3] or 0 end
        local ch4 = d_0x11llIl:sub(i_0xI1IllI+3,i_0xI1IllI+3)
        if ch4 == "=" then has4 = false else c_0xll1II1 = b64_0xl1Ill1[ch4] or 0 end
        local b_0xl1ll1I = c_0xIIl1II * (2^18) + c_0xlII1l1 * (2^12) + c_0xllIIII * (2^6) + c_0xll1II1
        local b_0xIlllII = math.floor(b_0xl1ll1I / (2^16)) % (2^8)
        local b_0x1IlIIl = math.floor(b_0xl1ll1I / (2^8)) % (2^8)
        local b_0xIlII11 = b_0xl1ll1I % (2^8)
        table.insert(r_0x1lIIlI, string.char(b_0xIlllII))
        if has3 then table.insert(r_0x1lIIlI, string.char(b_0x1IlIIl)) end
        if has4 then table.insert(r_0x1lIIlI, string.char(b_0xIlII11)) end
