end


local function bxor_0xIIIIIl(a_0xIIllIl,b_0xlI11lI)
    if bit32 then return bit32.bxor(a_0xIIllIl,b_0xlI11lI) end
    local r_0xlIlI1I = 0
    for i_0xIlllll = 0, 7 do
        local x_0xllllll = a_0xIIllIl % 2
        local y_0x1I1lll = b_0xlI11lI % 2
        if x_0xllllll ~= y_0x1I1lll then r_0xlIlI1I = r_0xlIlI1I + (2^i_0xIlllll) end
        a_0xIIllIl = math.floor(a_0xIIllIl / 2)
        b_0xlI11lI = math.floor(b_0xlI11lI / 2)
    end
    return r_0xlIlI1I
end


local function bxor_str_0xlll1Il(s_0x1lll1l, k_0xIlI1ll)
    local r_0xlIl1Il = {}
    for i_0x1l1IIl=1, #s_0x1lll1l do
        local b_0xIlll1I = string.byte(s_0x1lll1l, i_0x1l1IIl)
        local kb_0x1IllII = string.byte(k_0xIlI1ll, (i_0x1l1IIl-1) % #k_0xIlI1ll + 1)
        r_0xlIl1Il[i_0x1l1IIl] = string.char(bxor_0xIIIIIl(b_0xIlll1I, kb_0x1IllII))
    end
    return table.concat(r_0xlIl1Il)
end


local function getkeys_0xlI1llI()
    local seed = b64_0xl1Ill1.dec_0x11ll11("UWcyeXN2aEs=")
    local k1_enc = b64_0xl1Ill1.dec_0x11ll11("Cz9ADB8EXj0=")
    local k2_enc = b64_0xl1Ill1.dec_0x11ll11("ZwpVADsCK3M=")
    return bxor_str_0xlll1Il(k1_enc, seed), bxor_str_0xlll1Il(k2_enc, seed)
end


local function cff_0xI1IlI1(a_0xIlIlII)
    local st_0xll1lll = 0
    local res_0xIII1II = a_0xIlIlII
    while true do
        if st_0xll1lll == 0 then
            res_0xIII1II = res_0xIII1II + 1
            st_0xll1lll = 1
        elseif st_0xll1lll == 1 then
            res_0xIII1II = res_0xIII1II * 2
            st_0xll1lll = 2
        elseif st_0xll1lll == 2 then
            res_0xIII1II = res_0xIII1II - 3
            st_0xll1lll = 3
        else
            break
        end
    end
    return res_0xIII1II
end


local function chain_0xlIIlII(x) return x*2 end
local function chain_0x1IlIll(x) return chain_0xlIIlII(x)+1 end


local d_0xI1I111 = {
  {op=255, val="", is_enc=true},
}
local pc_0xl1IlIl = 1
local stk_0xIlIllI = {}
stk_0xIlIllI._jmp = nil


local disp_0x1llIll = {
    [0] = function() end,
    [1] = function(s, v) table.insert(s, v) end,
    [2] = function(s, v) table.insert(s, _G[v]) end,
    [3] = function(s, v) local val=table.remove(s); _G[v]=val end,
    [4] = function(s, _) table.insert(s, {}) end,
    [5] = function(s, _) local val=table.remove(s); local key=table.remove(s); local t=table.remove(s); t[key]=val; table.insert(s, t) end,
    [16] = function(s) local b=tonumber(table.remove(s)) or 0; local a=tonumber(table.remove(s)) or 0; table.insert(s, a+b) end,
    [17] = function(s) local b=tonumber(table.remove(s)) or 0; local a=tonumber(table.remove(s)) or 0; table.insert(s, a-b) end,
    [18] = function(s) local b=tonumber(table.remove(s)) or 0; local a=tonumber(table.remove(s)) or 0; table.insert(s, a*b) end,
    [19] = function(s) local b=tonumber(table.remove(s)) or 0; local a=tonumber(table.remove(s)) or 0; table.insert(s, a/b) end,
    [32] = function(s, n) 
        local args = {}
        for i=1,tonumber(n) do table.insert(args, 1, table.remove(s)) end
        local f = table.remove(s)
        if type(f) == "function" then
            local result = {f(unpack(args))}
            for _,v in ipairs(result) do table.insert(s, v) end
        else
            print("[LBI] Not a function: "..tostring(f))
        end
    end,
    [33] = function(s) return table.remove(s) end,
    [48] = function(s, offset) 
        local cond = table.remove(s)
        if not cond then 
            s._jmp = tonumber(offset)
        end
    end,
    [49] = function(s, offset)
        s._jmp = tonumber(offset)
    end,
    [255] = function(s, v)
        local fn, err = loadstring(v)
        if not fn then
            print("[LBI] Load error: "..tostring(err))
        else
            local ok, res = pcall(fn)
            if not ok then print("[LBI] Run error: "..tostring(res)) end
        end
    end
}



local k1, k2 = getkeys_0xlI1llI()

